import React from "react";
import "./BatchAnalysis.css";

function BatchAnalysis({ onFileChange, onAnalyze, loading, results, selectedFile }) {
  const handleFileSelect = (e) => {
    if (e.target.files.length > 0) {
      onFileChange(e);
    }
  };

  const renderResults = () => {
    if (!results) return null;

    return (
      <div className="batch-results">
        <h3>📊 Batch Analysis Results</h3>
        
        <div className="batch-stats">
          <div className="stat-card">
            <span className="stat-value">{results.total_records || results.processed_count || 0}</span>
            <span className="stat-label">Total Processed</span>
          </div>
          
          <div className="stat-card">
            <span className="stat-value">{results.churn_count || results.high_risk_count || 0}</span>
            <span className="stat-label">Churn Predictions</span>
          </div>
          
          <div className="stat-card">
            <span className="stat-value">
              {((results.churn_rate || (results.high_risk_count / results.total_records) || 0) * 100).toFixed(1)}%
            </span>
            <span className="stat-label">Churn Rate</span>
          </div>
        </div>

        {results.download_url && (
          <div className="download-section">
            <a href={results.download_url} download className="export-btn primary">
              <span className="btn-icon">📥</span>
              Download Detailed Results
            </a>
          </div>
        )}

        <details className="raw-data">
          <summary>View Complete Results</summary>
          <pre>{JSON.stringify(results, null, 2)}</pre>
        </details>
      </div>
    );
  };

  return (
    <div className="batch-analysis">
      <div className="analysis-container">
        <div className="section-card">
          <div className="file-upload-area">
            <input
              type="file"
              accept=".csv"
              onChange={handleFileSelect}
              className="file-input"
              id="batch-file"
            />
            <label htmlFor="batch-file" className="file-label">
              <span className="btn-icon">📎</span>
              Choose CSV File
            </label>
            
            {selectedFile && (
              <div className="file-info">
                <span className="file-success">✅</span>
                <div className="file-details">
                  <strong>{selectedFile.name}</strong>
                  <span>{(selectedFile.size / 1024).toFixed(1)} KB</span>
                </div>
              </div>
            )}
            
            <div className="file-requirements">
              <p><small>Required format: CSV with customer features matching individual analysis fields</small></p>
            </div>
          </div>

          <div className="action-buttons-bottom">
            <button 
              className="action-btn primary" 
              onClick={onAnalyze} 
              disabled={loading || !selectedFile}
            >
              {loading ? (
                <>
                  <div className="spinner"></div>
                  Processing Batch...
                </>
              ) : (
                <>
                  <span className="btn-icon">🚀</span>
                  Analyze Batch
                </>
              )}
            </button>
          </div>
        </div>

        {renderResults()}
      </div>
    </div>
  );
}

export default BatchAnalysis;
